  it("should NOT treat 4 alike runes as a block (charge each rune individually)", () => {
    const result = runScenario({
      command: "quote",
      customer: { yearsInsured: 0, contractNumber: 1 },
      items: [
        { type: "rune", material: "stone", enchantment: 0, cursed: false },
        { type: "rune", material: "stone", enchantment: 0, cursed: false },
        { type: "rune", material: "stone", enchantment: 0, cursed: false },
        { type: "rune", material: "stone", enchantment: 0, cursed: false },
      ],
    });
    expect(result).toEqual({ premium: 115 });
  });
  it("should NOT treat 2 alike runes as a block (charge each rune individually)", () => {
    const result = runScenario({
      command: "quote",
      customer: { yearsInsured: 0, contractNumber: 1 },
      items: [
        { type: "rune", material: "stone", enchantment: 0, cursed: false },
        { type: "rune", material: "stone", enchantment: 0, cursed: false },
      ],
    });
    expect(result).toEqual({ premium: 60 });
  });

  // === Quote: item-specific modifiers ===
  it("should add 50% cursed surcharge on a cursed item's base premium", () => {
    const result = runScenario({
      command: "quote",
      customer: { yearsInsured: 0, contractNumber: 1 },
      items: [{ type: "sword", material: "steel", enchantment: 0, cursed: true }],
    });
    expect(result).toEqual({ premium: 165 });
  });
  it("should add 30% high-enchantment surcharge for an item with enchantment >= 5", () => {
    const result = runScenario({
      command: "quote",
      customer: { yearsInsured: 0, contractNumber: 1 },
      items: [{ type: "sword", material: "steel", enchantment: 5, cursed: false }],
    });
    expect(result).toEqual({ premium: 145 });
  });
  it("should NOT add high-enchantment surcharge for enchantment level < 5", () => {
    const result = runScenario({
      command: "quote",
      customer: { yearsInsured: 0, contractNumber: 1 },
      items: [{ type: "sword", material: "steel", enchantment: 4, cursed: false }],
    });
    expect(result).toEqual({ premium: 115 });
  });
  it("should stack cursed and high-enchantment surcharges additively on the item's base premium", () => {
    const result = runScenario({
      command: "quote",
      customer: { yearsInsured: 0, contractNumber: 1 },
      items: [{ type: "sword", material: "steel", enchantment: 5, cursed: true }],
    });
    expect(result).toEqual({ premium: 195 });
  });

  // === Quote: policy-wide modifiers ===
  it("should apply -20% loyalty discount when customer has been insured for >= 2 years", () => {
    const result = runScenario({
      command: "quote",
      customer: { yearsInsured: 3, contractNumber: 1 },
      items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
    });
    expect(result).toEqual({ premium: 95 });
  });
  it.todo("should NOT apply loyalty discount when customer has been insured < 2 years");
  it.todo("should apply -15% follow-up discount for the customer's second contract");
  it.todo("should NOT apply follow-up discount for the customer's first contract");

  // === Quote: multiple items of same type (separate insurance) ===
  it.todo("should treat two swords as separate insurance entries (each charged individually)");

  // === Quote: rounding ===
  it.todo("should round the final premium UP to whole G in MHPCO's favor");

  // === Quote: integration examples from spec ===
  it.todo("should quote newcomer's cursed sword (steel, enchantment 3) at 165 G");
  it.todo("should quote 3-year customer's 2nd contract cursed sword (steel, enchantment 7) at 160 G");

  // === Claim: basic single damage ===
  it.todo("should pay out damage minus 100 G deductible for a single damaged item");
  it.todo("should report remainingCap as 2x unmodified insurance sum minus payout after a claim");

  // === Claim: enchantment and material clauses ===
  it.todo("should pay only 50% reimbursement when damaged item has enchantment >= 8");
  it.todo("should pay full reimbursement when damaged item is made of dragon material (overrides 50% clause)");
  it.todo("should NOT apply enchantment/material clauses to runes or moonstones");

  // === Claim: cap enforcement ===
  it.todo("should cap total payout at 2x unmodified insurance sum across multiple claim events");
  it.todo("should round payout DOWN to whole G in MHPCO's favor");

  // === CLI integration / error cases ===
  it.todo("should exit non-zero and write to stderr when quote contains an unknown item type");
  it.todo("should exit non-zero when a claim references an item not in the policy");
  it.todo("should exit non-zero when a claim has more damage entries of a type than the policy covers");
  it.todo("should exit non-zero when a claim contains a negative damage amount");
});

